mapper.select:
SELECT
    MAX(USERID) KEEP(DENSE_RANK LAST ORDER BY SYS_RDATE) USERID
FROM MCP_USER
WHERE NAME = #{customerNm}
AND MOBILE_NO = #{mobileNo}

mapper.insert:
 INSERT INTO NMCP_APY_NOTI_TXN (
     USER_ID
   , CSTMR_CI                 --본인인증한  CI 정보
   , MOBILE_CARRIER_CD        --현재이용중인통신사(MB0015)
   , MOBILE_COMPANY_CD        --현재이용중인 휴대폰 브랜드(MB0016)
   , MOBILE_MODEL_NM          --사용중인 휴대폰 기종
   , AUTH_INFO                --인증정보
   , NOTI_DIV_CD
   , NOTI_APY_DATE
   , NOTI_TRT_STTUS_CD
   , NOTI_SND_DT
   , NOTI_WAY_CD
   , NOTI_CD
   , CRET_IP
   , CRET_DT
   , CRET_ID
   , AMD_IP
   , AMD_DT
   , AMD_ID
   , NM
   , MOBILE_NO
 ) VALUES (
     #{userId}
   , #{cstmrCi}
   , #{mobileCarrierCd}
   , #{mobileCompanyCd}
   , #{mobileModelNm}
   , #{authInfo}
   , 'NOTI001'
   , #{expiryDate}||'000000'
   , 'A'
   , NULL
   , ''
   , ''
   , #{cretIp}
   , SYSDATE
   , #{userId}
   , #{amdIp}
   , SYSDATE
   , ''
   , #{customerNm}
   , #{mobileNo}
)
